// Acessa o dado "output" de forma dinâmica
const output = $input.first().json.output;

// Função para tratar e limpar a mensagem
const processOutput = (data) => {
  let result = data;

  // Remove bloco [DADOS] se existir (não enviar pro paciente)
  if (typeof result === 'string') {
    result = result.replace(/\[DADOS\][\s\S]*?\[\/DADOS\]/g, '').trim();
  }

  try {
    // Caso o conteúdo seja um JSON válido dentro da string, parse para acessar "mensagem"
    if (typeof result === 'string' && result.trim().startsWith('{') && result.trim().endsWith('}')) {
      const parsed = JSON.parse(result); // Tentar converter para JSON
      if (parsed.mensagem) {
        result = parsed.mensagem; // Extrair a mensagem se existir
      }
    } else {
      // Tentar converter a string como JSON caso tenha aspas escapadas
      result = JSON.parse(result);
    }
  } catch (error) {
    // Se falhar, significa que já é uma string normal
  }

  // Se ainda tiver o prefixo "mensagem", removê-lo
  if (typeof result === 'string' && result.includes('"mensagem":')) {
    result = result.split('"mensagem":')[1];
  }

  // Remover aspas no início e no final da string
  if (typeof result === 'string') {
    result = result.trim().replace(/^"+|"+$/g, '');
  }

  return result;
};

// Processa a saída e divide mensagens longas
const cleanOutput = processOutput(output);
const splitMessages = cleanOutput.split('\n').map(msg => msg.trim()).filter(msg => msg.length > 0);

// Retorna no formato desejado
return {
  messages: splitMessages
};

// v7: Extrair Dados roda DIRETO da msg do paciente (sem depender de LLM)
const estado_atual = $('Buscar Estado').first().json;
const userMsg = ($('Acumula').first().json.propertyName || '').toString().trim();
const userLower = userMsg.toLowerCase();

const dados = {};
let temDados = false;
const msgLimpa = ''; // legado: não há mais output do LLM nesse ponto

const has = (k) => !!(estado_atual[k] && estado_atual[k] !== '');

// --- tipo_consulta via regex (sempre tenta, independe de askingField) ---
let tipo = estado_atual.tipo_consulta || '';
if (!tipo) {
  if (/\bprimeira\b|primeira vez|\bnova\b|\bnunca\b/i.test(userLower)) {
    tipo = '1a_consulta';
    dados.tipo_consulta = tipo;
    temDados = true;
  } else if (/já sou|ja sou|já fui|ja fui|\bvoltando\b|\breconsulta\b|\bretorno\b/i.test(userLower)) {
    tipo = 'reconsulta';
    dados.tipo_consulta = tipo;
    temDados = true;
  }
}
// (reclassificação 12 meses agora é tratada via askingField='12_meses' abaixo)
// --- modalidade via regex (sempre tenta) ---
let modalidade = estado_atual.modalidade || '';
if (!modalidade) {
  if (/\bpresencial\b|consultório|consultorio|pessoalmente|\bfísico\b|\bfisico\b/i.test(userLower)) {
    modalidade = 'presencial';
    dados.modalidade = modalidade;
    temDados = true;
  } else if (/\bonline\b|videochamada|\bvídeo\b|\bvideo\b|\bremoto\b/i.test(userLower)) {
    modalidade = 'online';
    dados.modalidade = modalidade;
    temDados = true;
  }
}

function maybeSet(key, val) {
  if (val && !dados[key]) {
    dados[key] = val;
    temDados = true;
  }
}

// === askingField PRÉ-EXTRAÇÃO (o que o sistema acabou de perguntar) ===
// Cascata: tipo_consulta → 12_meses (só reconsulta) → modalidade → campos por cenário
const confirmou12 = (estado_atual.confirmou_12_meses && estado_atual.confirmou_12_meses !== '');
let askingField = null;
if (!tipo) askingField = 'tipo_consulta';
else if (tipo === 'reconsulta' && !confirmou12) askingField = '12_meses';
else if (!modalidade) askingField = 'modalidade';
else if (tipo === '1a_consulta') {
  if (!has('nome')) askingField = 'nome';
  else if (!has('data_nascimento')) askingField = 'data_nascimento';
  else if (!has('cpf')) askingField = 'cpf';
  else if (!has('altura')) askingField = 'altura';
  else if (!has('email')) askingField = 'email';
  else if (!has('endereco')) askingField = 'endereco';
  else if (!has('cep')) askingField = 'cep';
  else if (modalidade === 'presencial' && !has('condicao_saude')) askingField = 'condicao_saude';
} else if (tipo === 'reconsulta') {
  if (!has('nome')) askingField = 'nome';
  else if (!has('cpf')) askingField = 'cpf';
}

// Aplica parser contextual SÓ pro campo perguntado
if (askingField === '12_meses') {
  if (/mais de 12|mais de um ano|faz tempo|faz muito|\bmais\b|\bsim\b/i.test(userLower)) {
    // reclassifica reconsulta antiga como 1ª consulta
    tipo = '1a_consulta';
    dados.tipo_consulta = '1a_consulta';
    dados.confirmou_12_meses = 'sim';
    temDados = true;
  } else if (/menos de 12|menos de um ano|\brecente\b|\bpouco\b|\bmenos\b|\bnão\b|\bnao\b/i.test(userLower)) {
    // mantém como reconsulta
    dados.confirmou_12_meses = 'sim';
    temDados = true;
  }
}
else if (askingField === 'nome') {
  // v7 filtro de nome: rejeita palavras-comando e respostas de outras perguntas
  const rejeitados = /^(agendar|agendamento|marcar|consulta|oi|ol[áa]|bom dia|boa tarde|boa noite|sim|n[ãa]o|ok|obrigad[oa]?|quero|gostaria|preciso|pode|poderia|por favor|pfv|pf|online|presencial|primeira|primeiro|j[áa] sou|reconsulta|retorno)$/i;
  const limpo = userMsg.replace(/[\[\]{}]/g, '').trim();
  const aceita = limpo.length >= 4 && !/^\d+$/.test(limpo) && !rejeitados.test(limpo);
  if (aceita) {
    maybeSet('nome', limpo);
  }
}
else if (askingField === 'data_nascimento') {
  // Accept DD/MM/YYYY, DD-MM-YYYY, DDMMYYYY
  const m = userMsg.match(/(\d{2})[\/\-]?(\d{2})[\/\-]?(\d{4})/);
  if (m) {
    const d = m[1], mo = m[2], y = m[3];
    if (parseInt(d) <= 31 && parseInt(mo) <= 12 && parseInt(y) >= 1900 && parseInt(y) <= 2020) {
      maybeSet('data_nascimento', d + '/' + mo + '/' + y);
    }
  }
}
else if (askingField === 'cpf') {
  // CPF: 11 digits, with or without formatting
  const m = userMsg.match(/(\d{3}\.?\d{3}\.?\d{3}-?\d{2})/);
  if (m) {
    const clean = m[1].replace(/[.\-]/g, '');
    if (clean.length === 11) maybeSet('cpf', clean);
  }
}
else if (askingField === 'altura') {
  if (userLower.includes('não sei') || userLower.includes('nao sei') || userLower === 'nao' || userLower === 'não') {
    maybeSet('altura', 'não informada');
  } else {
    // Try meters: 1,75m or 1.75m or 1,75 or 1.75
    let m = userMsg.match(/(\d)[,.]\s*(\d{2})\s*m?/);
    if (m) {
      const num = parseFloat(m[1] + '.' + m[2]);
      if (num >= 1.0 && num <= 2.5) {
        maybeSet('altura', m[1] + ',' + m[2] + 'm');
      }
    } else {
      // Try cm: 175cm or 175
      m = userMsg.match(/(\d{3})\s*cm?/i) || userMsg.match(/^(\d{3})$/);
      if (m) {
        const cm = parseInt(m[1]);
        if (cm >= 100 && cm <= 250) {
          const meters = (cm / 100).toFixed(2).replace('.', ',');
          maybeSet('altura', meters + 'm');
        }
      }
    }
  }
}
else if (askingField === 'email') {
  const m = userMsg.match(/[\w.+-]+@[\w-]+\.[\w.-]+/);
  if (m) maybeSet('email', m[0]);
}
else if (askingField === 'endereco') {
  // Endereço: anything the user wrote (it's a free-text field)
  if (userMsg.length > 3) {
    maybeSet('endereco', userMsg.trim());
  }
}
else if (askingField === 'cep') {
  // CEP: 8 digits, with or without dash
  const m = userMsg.match(/(\d{5}-?\d{3})/);
  if (m) {
    const clean = m[1].replace(/-/g, '');
    if (clean.length === 8) maybeSet('cep', clean);
  } else {
    // Tolerate 7-digit typo (paciente errou) — accept anyway
    const m2 = userMsg.match(/(\d{7,8})/);
    if (m2) maybeSet('cep', m2[1]);
  }
}
else if (askingField === 'condicao_saude') {
  if (userLower === 'nenhuma' || userLower === 'nenhum' || userLower === 'nada' || userLower === 'não' || userLower === 'nao' || userLower === 'n') {
    maybeSet('condicao_saude', 'nenhuma');
  } else if (userLower.includes('gestant') || userLower.includes('gravid') || userLower.includes('grávid')) {
    maybeSet('condicao_saude', 'gestante');
  } else if (userLower.includes('marca-passo') || userLower.includes('marca passo') || userLower.includes('marcapasso')) {
    maybeSet('condicao_saude', 'marcapasso');
  } else if (userLower.includes('prótese') || userLower.includes('protese')) {
    maybeSet('condicao_saude', 'protese');
  }
}

// === STEP 3: Merge with existing state ===
const nome = dados.nome || estado_atual.nome || '';
const cpf = dados.cpf || estado_atual.cpf || '';
const nascimento = dados.data_nascimento || dados.nascimento || estado_atual.data_nascimento || '';
const email = dados.email || estado_atual.email || '';
const altura = dados.altura || estado_atual.altura || '';
const endereco = dados.endereco || estado_atual.endereco || '';
const cep = dados.cep || estado_atual.cep || '';
const condicao_saude = dados.condicao_saude || estado_atual.condicao_saude || '';
const confirmou_12_meses = dados.confirmou_12_meses || estado_atual.confirmou_12_meses || '';

// === STEP 4: Completeness check ===
let todosDados = false;
if (tipo === 'reconsulta') {
  todosDados = !!(nome && cpf && modalidade);
} else if (tipo === '1a_consulta') {
  if (modalidade === 'presencial') {
    todosDados = !!(nome && cpf && email && endereco && cep && altura && nascimento && condicao_saude);
  } else if (modalidade === 'online') {
    todosDados = !!(nome && cpf && email && endereco && cep && altura && nascimento);
  }
}

const novoEstado = todosDados ? 'dados_ok' : 'coletando_dados';

const dadosFinal = {
  nome, tipo_consulta: tipo, modalidade, cpf,
  data_nascimento: nascimento, email, altura, endereco, cep, condicao_saude, confirmou_12_meses
};

return [{
  json: {
    mensagem: msgLimpa,
    dados: dadosFinal,
    temDados: temDados,
    novoEstado: novoEstado,
    dadosCompletos: todosDados,
    askingField: askingField,
    nome, tipo_consulta: tipo, modalidade, cpf,
    data_nascimento: nascimento, email, altura, endereco, cep, condicao_saude, confirmou_12_meses
  }
}];

function limparMensagem(texto) {
  if (typeof texto !== 'string') {
    return '';
  }

  // Função para remover metadados e dados técnicos
  function removerMetadataTecnico(str) {
    return str
      // Remove objetos e chaves de metadados específicos
      .replace(/"response_metadata"\s*:\s*{[^}]*}/g, '')  // Remove "response_metadata"
      .replace(/"additional_kwargs"\s*:\s*{[^}]*}/g, '')  // Remove "additional_kwargs"
      .replace(/"tool_calls"\s*:\s*\[\s*\]/g, '')  // Remove "tool_calls" vazio
      .replace(/"invalid_tool_calls"\s*:\s*\[\s*\]/g, '')  // Remove "invalid_tool_calls" vazio
      .replace(/"type"\s*:\s*"(ai|human)"/g, '')  // Remove os tipos "ai" e "human"
      .replace(/"data"\s*:\s*{[^}]*}/g, '')  // Remove a chave "data"
      // Remove objetos JSON em excesso ou vazios
      .replace(/,\s*{[^}]*}/g, '') // Remove objetos soltos
      .replace(/,\s*\[\s*\]/g, '') // Remove arrays vazios
      .replace(/\s*:\s*null/g, '') // Remove valores null
      .replace(/\s*:\s*\[\]/g, '') // Remove arrays vazios
      .replace(/\s*:\s*{}/g, '') // Remove objetos vazios
      // Ajusta espaços desnecessários
      .replace(/\s+/g, ' ')
      .replace(/^\s+|\s+$/g, '');  // Remove espaços no início e fim
  }

  // Função para limpar caracteres especiais
  function limparCaracteresEspeciais(str) {
    return str
      .replace(/\\\\[rnt]/g, ' ')  // Limpa sequências de escape
      .replace(/\\\\\"/g, '')  // Remove as aspas escapadas
      .replace(/\\\\\\\\/g, '')  // Remove barras invertidas
      .replace(/[\x00-\x1F\x7F-\x9F]/g, '')  // Remove caracteres de controle
      .replace(/\"+/g, '')  // Remove aspas extras
      .replace(/[{}[\]]/g, '')  // Remove chaves e colchetes extras
      .trim();
  }

  // Função para extrair e limpar a mensagem principal
  function extrairMensagemPrincipal(str) {
    // Divide em frases, removendo pontuação extra
    const frases = str.split(/(?<=[.!?])\s+/);

    return frases
      .map(frase => frase.trim())
      .filter(frase => {
        // Remove frases que ainda têm metadados ou são irrelevantes
        return frase.length > 0 &&
          !frase.includes('tool_calls') &&
          !frase.includes('invalid_tool_calls') &&
          !frase.match(/^[:\s\[\]{}]+$/);
      })
      .join(' ');
  }

  // Processo de limpeza e extração
  let resultado = texto;

  // Passo 1: Remove metadados e chaves indesejadas
  resultado = removerMetadataTecnico(resultado);

  // Passo 2: Extrai a mensagem relevante, ignorando o que não é necessário
  resultado = extrairMensagemPrincipal(resultado);

  // Passo 3: Remove caracteres especiais e formatação indesejada
  resultado = limparCaracteresEspeciais(resultado);

  // Limpeza final para remover espaços extras
  resultado = resultado
    .replace(/\s+/g, ' ')
    .replace(/^[\",\s]+|[\",\s]+$/g, '')
    .trim();

  return resultado;
}

function processarMensagens(items) {
  return items.map(item => {
    try {
      if (!item?.json?.mensagem) {
        return item;
      }

      let mensagem = item.json.mensagem;

      // Se for objeto, converte para string
      if (typeof mensagem === 'object') {
        try {
          mensagem = JSON.stringify(mensagem);
        } catch (e) {
          console.error('Erro ao converter objeto para string:', e);
          return item;
        }
      }

      // Aplica a limpeza
      const mensagemLimpa = limparMensagem(mensagem);

      // Atualiza apenas se houver conteúdo significativo
      if (mensagemLimpa && mensagemLimpa.length > 0) {
        item.json.mensagem = mensagemLimpa;
      }

      return { json: item.json };
    } catch (error) {
      console.error('Erro ao processar item:', error);
      return item;
    }
  });
}

// Execução principal
try {
  const items = $input.all();
  return processarMensagens(items);
} catch (error) {
  console.error('Erro na execução:', error);
  throw error;
}

