// v7: mapa determinístico de perguntas. Lê estado fresco do Postgres e decide próxima pergunta.
const e = $input.first().json;
const tipo = (e.tipo_consulta || '').toString();
const modalidade = (e.modalidade || '').toString();
const has = (k) => !!(e[k] && e[k].toString().trim() !== '');

// askingField anterior (o que acabou de ser respondido) — vem do Extrair Dados
const extraidoPrev = $('Extrair Dados').first().json;
const askingFieldAnterior = extraidoPrev.askingField || '';
// 12_meses captura no campo confirmou_12_meses, não no homônimo
const chaveDado = askingFieldAnterior === '12_meses' ? 'confirmou_12_meses' : askingFieldAnterior;
const valorCapturado = (extraidoPrev.dados && extraidoPrev.dados[chaveDado]) || '';

// Decide o próximo campo a perguntar
const confirmou12 = has('confirmou_12_meses');
let askingField = null;
if (!tipo) askingField = 'tipo_consulta';
else if (tipo === 'reconsulta' && !confirmou12) askingField = '12_meses';
else if (!modalidade) askingField = 'modalidade';
else if (tipo === '1a_consulta') {
  if (!has('nome')) askingField = 'nome';
  else if (!has('data_nascimento')) askingField = 'data_nascimento';
  else if (!has('cpf')) askingField = 'cpf';
  else if (!has('altura')) askingField = 'altura';
  else if (!has('email')) askingField = 'email';
  else if (!has('endereco')) askingField = 'endereco';
  else if (!has('cep')) askingField = 'cep';
  else if (modalidade === 'presencial' && !has('condicao_saude')) askingField = 'condicao_saude';
  else askingField = 'dados_completos';
} else if (tipo === 'reconsulta') {
  if (!has('nome')) askingField = 'nome';
  else if (!has('cpf')) askingField = 'cpf';
  else askingField = 'dados_completos';
} else {
  askingField = 'tipo_consulta';
}

const PERGUNTAS = {
  tipo_consulta: 'Será sua primeira consulta com a Renata, ou você já é paciente?',
  '12_meses': 'Faz mais ou menos de 12 meses desde a sua última consulta com a Renata?',
  modalidade: 'Você prefere atendimento presencial (no consultório, em Porto Alegre) ou online (por videochamada)?',
  nome: 'Para começar, por gentileza, me informe seu nome completo.',
  data_nascimento: 'Agora, me informe sua data de nascimento (formato DD/MM/AAAA).',
  cpf: 'Por favor, me passe seu CPF (apenas números, sem pontos ou traços).',
  altura: "Qual a sua altura? Pode me informar em metros (ex: 1,75m) ou em centímetros (ex: 175cm). Caso não saiba, me diga 'não sei' que a Renata avalia no dia.",
  email: 'Por gentileza, me informe seu e-mail.',
  endereco: 'Agora, me informe o endereço completo (rua e número).',
  cep: 'Por fim do endereço, me informe o CEP (apenas números).',
  condicao_saude: 'Antes de finalizar, preciso confirmar uma informação importante para o exame de bioimpedância: você possui alguma das seguintes condições — gestação, marca-passo ou prótese metálica?',
  dados_completos: 'Seus dados foram registrados. Vou verificar os horários disponíveis para você.'
};

const pergunta = PERGUNTAS[askingField] || '';

return [{
  json: {
    askingField,
    askingFieldAnterior,
    valorCapturado,
    pergunta,
    dados_completos: askingField === 'dados_completos'
  }
}];

// v7.1: junta pergunta determinística + (opcionalmente) confirmação do LLM.
// Se askingField for um campo inicial (tipo_consulta, modalidade, 12_meses), pula a confirmação.
const mp = $('Montar Pergunta Cadastro').first().json;
const askingField = mp.askingField || '';
const pergunta = (mp.pergunta || '').toString().trim();
const valorCap = mp.valorCapturado || '';
const pulaCerebro = ['tipo_consulta','modalidade','12_meses','nome'].includes(askingField) || !valorCap || valorCap === '(nenhum)';

let confirmacao = '';
if (!pulaCerebro) {
  try {
    const raw = ($('Cérebro 1 — Cadastro').first().json.output || '').toString().trim();
    // Remove qualquer bloco [DADOS] ou [QUALQUER COISA] que o LLM possa vazar
    confirmacao = raw.replace(/\[[A-Z_\/]+\][\s\S]*?\[\/[A-Z_\/]+\]/g, '').replace(/\[[A-Z_\/]+\]/g, '').trim();
  } catch (e) {
    confirmacao = '';
  }
}

const partes = [confirmacao, pergunta].filter(s => s && s.length > 0);
const mensagem = partes.join('\n\n');

const splitMessages = mensagem.split('\n').map(m => m.trim()).filter(m => m.length > 0);

return {
  messages: splitMessages
};

const estado = $('Buscar Estado').first().json;
const estadoAtual = estado.estado || 'novo';
const mensagem = $('Acumula').first().json.propertyName || '';
const msgLower = mensagem.toLowerCase();

// Keywords de agendamento
const agendarKeywords = ['agendar', 'agendamento', 'marcar consulta', 'marcar horário', 'marcar horario', 'quero agendar', 'gostaria de agendar', 'quero marcar'];
const querAgendar = agendarKeywords.some(k => msgLower.includes(k));

// Se estado é 'novo' ou 'geral' ou 'agendado' e paciente quer agendar, mudar pra coletando_dados
let novoEstado = estadoAtual;
if ((estadoAtual === 'novo' || estadoAtual === 'geral' || estadoAtual === 'agendado') && querAgendar) {
  novoEstado = 'coletando_dados';
}

return [{
  json: {
    ...estado,
    estado: novoEstado,
    intencao_agendar: querAgendar
  }
}];

// Extract date, time and type from the confirmation message
const input = $input.first().json;
const tipo = input.tipo || 'reconsulta_presencial';
// Get tipo from Buscar Estado (reliable)
const estado_tipo = $('Buscar Estado').first().json;
const primeira = estado_tipo.tipo_consulta === '1a_consulta';
const online = (estado_tipo.modalidade || 'presencial') === 'online';

// Get the confirmation message
const codeOutput = $('Code').first().json;
const msgs = codeOutput.messages || [];
const txt = Array.isArray(msgs) ? msgs.join(' ') : String(msgs);

let startDate = '';
let startHour = 0;
let startMinute = 0;

// === EXTRACT DATE ===

// Pattern 1: DD-MM-YYYY or DD/MM/YYYY
let dateMatch = txt.match(/(\d{2})[-\/](\d{2})[-\/](\d{4})/);
if (dateMatch) {
  startDate = dateMatch[3] + '-' + dateMatch[2] + '-' + dateMatch[1];
}

// Pattern 1b: DD/MM without year (e.g. "06/05")
if (!startDate) {
  const shortDateMatch = txt.match(/(\d{2})\/(\d{2})(?!\/)/) || txt.match(/(\d{1,2})\/(\d{2})(?!\/)/);
  if (shortDateMatch) {
    const day = String(shortDateMatch[1]).padStart(2, '0');
    const month = String(shortDateMatch[2]).padStart(2, '0');
    const now = new Date();
    const spOffset = -3 * 60;
    const utc = now.getTime() + (now.getTimezoneOffset() * 60000);
    const spNow = new Date(utc + (spOffset * 60000));
    const currentYear = spNow.getFullYear();
    const currentMonth = spNow.getMonth() + 1;
    const mesNum = parseInt(month);
    const year = (mesNum < currentMonth || (mesNum === currentMonth && parseInt(day) < spNow.getDate())) ? currentYear + 1 : currentYear;
    startDate = year + '-' + month + '-' + day;
  }
}

// Pattern 2: "dia X de MONTH" or "dia XX de MONTH"
if (!startDate) {
  const meses = {
    'janeiro':'01','fevereiro':'02','março':'03','marco':'03','abril':'04',
    'maio':'05','junho':'06','julho':'07','agosto':'08','setembro':'09',
    'outubro':'10','novembro':'11','dezembro':'12'
  };
  const mesPat = txt.match(/dia\s+(\d{1,2})\s+de\s+(\w+)/i);
  if (mesPat) {
    const day = String(mesPat[1]).padStart(2, '0');
    const mesNome = mesPat[2].toLowerCase();
    const month = meses[mesNome];
    if (month) {
      const now = new Date();
      const currentYear = now.getFullYear();
      const currentMonth = now.getMonth() + 1;
      const mesNum = parseInt(month);
      const year = mesNum < currentMonth ? currentYear + 1 : currentYear;
      startDate = year + '-' + month + '-' + day;
    }
  }
}

// Pattern 3: day of week — calculate next occurrence from today
if (!startDate) {
  const diasSemana = {
    'segunda': 1, 'terça': 2, 'terca': 2, 'quarta': 3,
    'quinta': 4, 'sexta': 5
  };
  for (const [nome, dow] of Object.entries(diasSemana)) {
    if (txt.toLowerCase().includes(nome)) {
      const now = new Date();
      const spOffset = -3 * 60; // BRT = UTC-3
      const utc = now.getTime() + (now.getTimezoneOffset() * 60000);
      const spNow = new Date(utc + (spOffset * 60000));
      const currentDow = spNow.getDay();
      let daysAhead = dow - currentDow;
      if (daysAhead <= 0) daysAhead += 7;
      const target = new Date(spNow);
      target.setDate(target.getDate() + daysAhead);
      const y = target.getFullYear();
      const m = String(target.getMonth() + 1).padStart(2, '0');
      const d = String(target.getDate()).padStart(2, '0');
      startDate = y + '-' + m + '-' + d;
      break;
    }
  }
}

// === EXTRACT TIME ===
// "às 9h", "às 9 horas", "às 9h30min", "às 09:00", "às 14h30"
const timeMatch = txt.match(/às\s+(\d{1,2})(?:h|\s*horas?)(?:(\d{2})(?:min)?)?/i) ||
                  txt.match(/às\s+(\d{1,2}):(\d{2})/i);
if (timeMatch) {
  startHour = parseInt(timeMatch[1]);
  startMinute = timeMatch[2] ? parseInt(timeMatch[2]) : 0;
}

// === DURATION ===
const durationMin = (primeira && !online) ? 60 : 30;

// === BUILD DATETIME STRINGS ===
const startTimeStr = String(startHour).padStart(2,'0') + ':' + String(startMinute).padStart(2,'0') + ':00';
const endHour = startHour + Math.floor((startMinute + durationMin) / 60);
const endMin = (startMinute + durationMin) % 60;
const endTimeStr = String(endHour).padStart(2,'0') + ':' + String(endMin).padStart(2,'0') + ':00';

const startDateTime = startDate + 'T' + startTimeStr + '-03:00';
const endDateTime = startDate + 'T' + endTimeStr + '-03:00';

// === PATIENT DATA for description ===
const estado = $('Buscar Estado').first().json;
const nome = estado.nome || 'Paciente';
const cpf = estado.cpf || '';
const email = estado.email || '';
const nascimento = estado.data_nascimento || '';
const altura = estado.altura || '';
const endereco = estado.endereco || '';
const cep = estado.cep || '';
const telefone = $('Dados do Usuário').first().json.telefone || '';
const idUser = $('Dados do Usuário').first().json.idUser || '';
const modalidade = estado.modalidade || 'presencial';
const tipoLabel = primeira ? '1ª consulta' : 'reconsulta';

// Full description with all patient data
const description = [
  'Tipo: ' + tipoLabel + ' (' + modalidade + ')',
  'Nome: ' + nome,
  'CPF: ' + cpf,
  'Nascimento: ' + nascimento,
  'E-mail: ' + email,
  'Telefone: ' + telefone.replace('@s.whatsapp.net', ''),
  'Altura: ' + altura,
  'Endereço: ' + endereco + (cep ? ' - CEP: ' + cep : ''),
  'ID sessão: ' + idUser
].join('\n');

return [{
  json: {
    startDateTime,
    endDateTime,
    summary: 'Nutriskin — ' + nome + ' (' + tipoLabel + ')',
    description,
    nome,
    tipo: tipoLabel,
    dateFound: !!startDate,
    timeFound: !!timeMatch,
    durationMin,
    agendado: input.agendado,
    primeira,
    online,
    tipoOriginal: tipo
  }
}];

